export class Navigation {
    constructor() {
        this.element = null;
        this.init();
    }
    
    init() {
        this.element = document.createElement('nav');
        this.element.className = 'main-nav';
        this.element.innerHTML = `
            <div class="nav-container">
                <a href="/" class="nav-logo">
                    <img src="/assets/group-107.svg" alt="ISPER" class="logo-img">
                </a>
                
                <div class="nav-links">
                    <a href="/isper" class="nav-link">Isper Maps</a>
                    <a href="/company" class="nav-link">Company</a>
                    <a href="/news" class="nav-link">News</a>
                    <a href="/contact" class="nav-link">Contact</a>
                </div>
                
                <div class="nav-mobile-toggle">
                    <span></span>
                    <span></span>
                    <span></span>
                </div>
            </div>
            <style>
                @media (max-width: 768px) {
                    .nav-links:not(.active) {
                        border-bottom: none !important;
                    }
                }
            </style>
        `;
        
        this.setupMobileToggle();
        this.updateActiveLink();
        this.setupLinkHandlers();
    }
    
    setupMobileToggle() {
        const toggle = this.element.querySelector('.nav-mobile-toggle');
        const links = this.element.querySelector('.nav-links');
        const navLinks = this.element.querySelectorAll('.nav-link');
        
        toggle.addEventListener('click', () => {
            links.classList.toggle('active');
            toggle.classList.toggle('active');
        });
        
        // Close menu when clicking on a link
        navLinks.forEach(link => {
            link.addEventListener('click', () => {
                links.classList.remove('active');
                toggle.classList.remove('active');
            });
        });
    }
    
    setupLinkHandlers() {
        const links = this.element.querySelectorAll('.nav-link');
        const logo = this.element.querySelector('.nav-logo');
        
        // Handle navigation links
        links.forEach(link => {
            link.addEventListener('click', (e) => {
                const href = link.getAttribute('href');
                const currentPath = window.location.pathname;
                
                // Prevent navigation if already on the same page
                if (href === currentPath) {
                    e.preventDefault();
                }
            });
        });
        
        // Handle logo click
        logo.addEventListener('click', (e) => {
            const currentPath = window.location.pathname;
            
            // Prevent navigation if already on home page
            if (currentPath === '/' || currentPath === '') {
                e.preventDefault();
            }
        });
    }
    
    updateActiveLink() {
        const currentPath = window.location.pathname;
        const links = this.element.querySelectorAll('.nav-link');
        
        links.forEach(link => {
            if (link.getAttribute('href') === currentPath) {
                link.classList.add('active');
            } else {
                link.classList.remove('active');
            }
        });
    }
    
    render() {
        return this.element;
    }
}